import{GAME_CONFIG}from"../config.js";import{battleRecorder}from"./BattleRecorder.js";import{AI}from"../ai/AI.js";import{TurnSimulator}from"./TurnSimulator.js";import{AnimationPlayer}from"../render/AnimationPlayer.js";import{audioManager}from"../audio/AudioManager.js";class TurnManager{constructor(t){this.game=t,this.calculatedScript={},this.simulator=new TurnSimulator(this.game),this.player=new AnimationPlayer(this.game),this.ai=new AI(this.game)}initFirstTurn(){window.roundCount=1,gameState="PLANNING",console.log("Фаза планирования. Раздайте приказы персонажам.")}startTurnExecution(){"PLANNING"===window.gameState&&(this.ai.planAll(),audioManager.play("start_battle",.2),this.realSimulationStartTime=performance.now(),this.calculatedScript=this.simulator.calculateRoundScript(window.entities),this.player.play(this.calculatedScript),window.gameState="EXECUTION")}updateExecution(){var t;"EXECUTION"!==window.gameState||this.player.updatePlayback()||(t=(performance.now()-this.realSimulationStartTime)/1e3,console.log(`%c[TurnManager]: Сценарий раунда успешно воспроизведен за ${t.toFixed(3)} сек.`,"color: #00ff00; font-weight: bold;"),this.endTurnExecution())}endTurnExecution(){console.log("[TurnManager]: Все персонажи добежали. Возврат в фазу планирования."),window.gameState="PLANNING";window.entities.find(t=>"player"===t.type);window.entities&&window.entities.forEach(t=>{t.resetPlannedState()}),this.game.grid.plannedPath=[],this.game.grid.highlights=[],this.game.input._updateGridHighlights();var t=this.game.game.sceneManager.currentScene?.ui;t&&t.consoleUI&&(t.consoleUI.viewingRound=window.roundCount)}}export{TurnManager};